// HTML (string)
<div style="color: red; font-size: 14px; background-color: #fff">

// JSX (object — double braces: outer {} is JSX expression, inner {} is object literal)
<div style={{ color: 'red', fontSize: 14, backgroundColor: '#fff' }}>

function Tooltip({ x, y, visible, theme }) {
  return (
    <div
      style={{
        position: 'absolute',
        left: x,                              // number → pixels
        top: y,
        opacity: visible ? 1 : 0,            // conditional
        transform: `translateY(${visible ? 0 : 8}px)`, // template literal
        transition: 'opacity 150ms, transform 150ms',
        backgroundColor: theme === 'dark' ? '#1f2937' : '#fff',
        color: theme === 'dark' ? '#f9fafb' : '#111827',
      }}
    >
      content
    </div>
  );
}

// Setting custom properties through style
function ThemeProvider({ brandColor, children }) {
  return (
    <div style={{ '--brand-color': brandColor, '--brand-dark': darken(brandColor) }}>
      {children}
    </div>
  );
}

// CSS (in a stylesheet or CSS module)
// .button { background: var(--brand-color); }

const baseStyle = { fontSize: 14, color: '#333', padding: '8px 12px' };
const highlightStyle = { color: 'navy', fontWeight: 'bold' };

// highlightStyle.color overrides baseStyle.color
<div style={{ ...baseStyle, ...highlightStyle }}>

// Conditional layer
<div style={{ ...baseStyle, ...(isActive && highlightStyle) }}>

// Bad: new object every render
<Card style={{ padding: 16, borderRadius: 8 }} />

// Good: module-level constant
const CARD_STYLE = { padding: 16, borderRadius: 8 };
<Card style={CARD_STYLE} />

// Good: useMemo for dynamic values
function Chart({ width, height }) {
  const style = useMemo(() => ({ width, height }), [width, height]);
  return <canvas style={style} />;
}

import type { CSSProperties } from 'react';

interface CardProps {
  width: number;
  accent: string;
  children: React.ReactNode;
}

function Card({ width, accent, children }: CardProps) {
  const style: CSSProperties = {
    width,
    borderLeft: `4px solid ${accent}`,
    padding: '12px 16px',
    borderRadius: 6,
  };
  return <div style={style}>{children}</div>;
}

function FadeBox({ visible }) {
  return (
    <div
      style={{
        opacity: visible ? 1 : 0,
        transform: `translateY(${visible ? 0 : 12}px)`,
        transition: 'opacity 200ms ease, transform 200ms ease',
        pointerEvents: visible ? 'auto' : 'none',
      }}
    >
      content
    </div>
  );
}

// In a .css or .module.css file:
// @keyframes spin { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }

// In JSX — apply the animation via inline style:
<div style={{
  animationName: 'spin',
  animationDuration: '1s',
  animationTimingFunction: 'linear',
  animationIterationCount: 'infinite',
}} />

// Shorthand string value also works:
<div style={{ animation: 'spin 1s linear infinite' }} />

// Wrong: second transform wins, first is silently lost
<div style={{
  transform: `rotate(${angle}deg)`,
  transform: `scale(${scale})`,
}} />

// Correct: compose into one string
<div style={{
  transform: `rotate(${angle}deg) scale(${scale}) translateX(${x}px)`,
}} />

// With useMemo to avoid rebuilding on unrelated renders
const transform = useMemo(
  () => `rotate(${angle}deg) scale(${scale})`,
  [angle, scale]
);
<div style={{ transform }} />

// Server-rendered output contains inline styles in the HTML:
// <div style="background-color:#fff;padding:16px;opacity:1">...</div>

// Client hydration matches without a flash.
// CSS class styles need the stylesheet to load first.

function CriticalCard({ color }) {
  // color is in the HTML immediately — no flicker waiting for a stylesheet
  return <div style={{ backgroundColor: color, padding: 16 }}>{/* ... */}</div>;
}

// Reset font to browser default regardless of ancestor styles
<code style={{ fontSize: 'inherit', fontFamily: 'monospace' }}>
  {snippet}
</code>

// Isolate a component from parent text color
<figure style={{ color: 'initial' }}>
  {children}
</figure>

// Completely unset inherited properties
<blockquote style={{ fontStyle: 'unset', margin: 'unset' }}>
  {quote}
</blockquote>

// Anti-pattern: complex style logic inline
<div style={{
  ...(variant === 'primary' ? primaryStyles : dangerStyles),
  ...(size === 'sm' ? smStyles : lgStyles),
}}>

// Refactor: helper function keeps JSX clean
function getButtonStyle(variant, size) {
  const variantStyle = variant === 'primary' ? primaryStyles : dangerStyles;
  const sizeStyle = size === 'sm' ? smStyles : lgStyles;
  return { ...variantStyle, ...sizeStyle };
}

<div style={getButtonStyle(variant, size)}>

import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';

function Badge({ active }) {
  return (
    <span
      data-testid="badge"
      style={{ opacity: active ? 1 : 0.4, fontWeight: active ? 'bold' : 'normal' }}
    >
      Status
    </span>
  );
}

test('active badge is fully opaque and bold', () => {
  render(<Badge active={true} />);
  expect(screen.getByTestId('badge')).toHaveStyle({
    opacity: 1,
    fontWeight: 'bold',
  });
});

test('inactive badge is dimmed', () => {
  render(<Badge active={false} />);
  expect(screen.getByTestId('badge')).toHaveStyle('opacity: 0.4');
});
